UPDATE USER_ACCOUNTS 
SET BALANCE = BALANCE - #{amount}
WHERE USER_ID = #{userId} 
  AND IS_PRIMARY = 'Y' 
  AND BALANCE >= #{amount}

UPDATE GROUP_ACCOUNT 
SET BALANCE = BALANCE + #{amount}
WHERE GROUP_ID = #{groupId}

UPDATE GROUP_ACCOUNT
SET BALANCE = BALANCE + #{amount}
WHERE GROUP_ID = #{groupId}

UPDATE GROUP_MEMBERS
SET MEMBER_STATUS = 'KICKED',
    UPDATED_AT = CURRENT_TIMESTAMP
WHERE GROUP_ID = #{groupId}
  AND USER_ID = #{userId}
  AND GROUP_ROLE != 'HOST' -- 방장은 강퇴 방지

mapper.select:
SELECT COUNT(*)
FROM GROUP_MEMBERS
WHERE GROUP_ID = #{groupId}
  AND USER_ID = #{userId}
  AND MEMBER_STATUS = 'KICKED'

SELECT COUNT(*)
FROM GROUP_MEMBERS
WHERE GROUP_ID = #{groupId}
  AND USER_ID = #{userId}
  AND MEMBER_STATUS = 'JOINED'

SELECT GROUP_ROLE
FROM GROUP_MEMBERS
WHERE GROUP_ID = #{groupId}
  AND USER_ID = #{userId}
  AND MEMBER_STATUS = 'JOINED'

